#include <stdio.h>
int main() {
    int T, n, c, l, x;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        int max_discount[3] = {0, 0, 0};
        int city[3] = {0, 0, 0};
        for (int i = 0; i < n; i++) {
            scanf("%d %d %d", &c, &l, &x);
            l--;
            if (x > max_discount[l] || (x == max_discount[l] && c < city[l])) {
                max_discount[l] = x;
                city[l] = c;
            }
        }
        for (int i = 0; i < 3; i++) {
            printf("%d %d\n", max_discount[i], city[i]);
        }
    }
    return 0;
}

