import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] max_discount = new int[3];
            int[] city = new int[3];
            for (int i = 0; i < n; i++) {
                int c = sc.nextInt();
                int l = sc.nextInt() - 1;
                int x = sc.nextInt();
                if (x > max_discount[l] || (x == max_discount[l] && c < city[l])) {
                    max_discount[l] = x;
                    city[l] = c;
                }
            }
            for (int i = 0; i < 3; i++) {
                System.out.println(max_discount[i] + " " + city[i]);
            }
        }
    }
}

